mutation B2BContactLocationAssignmentsCreate($input: CompanyCreateInput!) {
  companyCreate(input: $input) {
    company {
      id
      name
      mainContact {
        id
        title
        isMainContact
        roleAssignments(first: 5) {
          nodes {
            id
            role {
              id
              name
            }
            companyLocation {
              id
              name
            }
          }
        }
      }
      contacts(first: 5) {
        nodes {
          id
          title
          isMainContact
          roleAssignments(first: 5) {
            nodes {
              id
              role {
                id
                name
              }
              companyLocation {
                id
                name
              }
            }
          }
        }
      }
      locations(first: 5) {
        nodes {
          id
          name
        }
      }
      contactRoles(first: 5) {
        nodes {
          id
          name
        }
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

query B2BColdCompaniesRead($query: String!) {
  companies(first: 3, query: $query) {
    nodes {
      id
      name
