query B2BMutationTargetsHydrate($ids: [ID!]!) {
  nodes(ids: $ids) {
    __typename
    id
    ... on Company {
      ...B2BHydrateCompany
    }
    ... on CompanyLocation {
      ...B2BHydrateLocation
      company { ...B2BHydrateCompanyReference }
    }
    ... on CompanyContact {
      ...B2BHydrateContact
      company { ...B2BHydrateCompanyReference }
    }
    ... on CompanyContactRole {
      ...B2BHydrateRole
    }
    ... on CompanyContactRoleAssignment {
      ...B2BHydrateRoleAssignment
      companyContact {
        ...B2BHydrateContact
        company { ...B2BHydrateCompanyReference }
      }
      companyLocation {
        ...B2BHydrateLocation
        company { ...B2BHydrateCompanyReference }
      }
    }
    ... on CompanyLocationStaffMemberAssignment {
      ...B2BHydrateStaffAssignment
      companyLocation {
        ...B2BHydrateLocation
        company { ...B2BHydrateCompanyReference }
      }
    }
    ... on CompanyAddress {
      ...B2BHydrateAddress
    }
    ... on Customer {
      ...B2BHydrateCustomer
      companyContactProfiles {
        ...B2BHydrateContact
        company { ...B2BHydrateCompanyReference }
      }
    }
    ... on StaffMember {
      id
    }
  }
}

